import azure.functions as func
import json
import logging
from datetime import datetime

app = func.FunctionApp()

@app.function_name(name="PaymentWebhook")
@app.route(route="webhook/payment", methods=["POST"], auth_level=func.AuthLevel.ANONYMOUS)
def payment_webhook(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Payment webhook triggered')
    
    try:
        req_body = req.get_json()
        
        payment_id = req_body.get('payment_id')
        status = req_body.get('status')
        amount = req_body.get('amount')
        currency = req_body.get('currency')
        provider = req_body.get('provider')
        timestamp = req_body.get('timestamp', datetime.utcnow().isoformat())
        
        if not all([payment_id, status, amount, currency, provider]):
            return func.HttpResponse(
                json.dumps({
                    "error": "Missing required fields",
                    "required": ["payment_id", "status", "amount", "currency", "provider"]
                }),
                status_code=400,
                mimetype="application/json"
            )
        
        payment_data = {
            "payment_id": payment_id,
            "status": status,
            "amount": amount,
            "currency": currency,
            "provider": provider,
            "timestamp": timestamp,
            "processed_at": datetime.utcnow().isoformat()
        }
        
        logging.info(f"Processing payment: {payment_id} with status: {status}")
        logging.info(f"Payment details: {json.dumps(payment_data)}")
        
        if status.lower() == 'success':
            logging.info(f"Payment {payment_id} completed successfully")
        elif status.lower() == 'failed':
            logging.warning(f"Payment {payment_id} failed")
        elif status.lower() == 'pending':
            logging.info(f"Payment {payment_id} is pending")
        
        response_data = {
            "message": "Payment notification received and processed",
            "payment_id": payment_id,
            "status": "acknowledged"
        }
        
        return func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json"
        )
    
    except ValueError as ve:
        logging.error(f"Invalid JSON payload: {str(ve)}")
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON payload"}),
            status_code=400,
            mimetype="application/json"
        )
    
    except Exception as e:
        logging.error(f"Error processing payment webhook: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": "Internal server error"}),
            status_code=500,
            mimetype="application/json"
        )